# Module providing utility functions for shape processing
# Demonstrates: higher-order functions, working with interfaces
from shapes import Measurable, Drawable, Rectangle, Circle

def total_area_rectangles(rects: list[Rectangle]) -> float:
    total: float = 0.0
    for r in rects:
        total = total + r.area()
    return total

def describe_all_rectangles(rects: list[Rectangle]) -> list[str]:
    descriptions: list[str] = []
    for r in rects:
        descriptions.append(r.draw())
    return descriptions

def filter_large_rectangles(rects: list[Rectangle]) -> list[Rectangle]:
    result: list[Rectangle] = []
    for r in rects:
        if r.area() > 10.0:
            result.append(r)
    return result

def scale_rectangle(r: Rectangle, factor: float) -> Rectangle:
    return Rectangle(r.width * factor, r.height * factor)

def get_rectangle_area(r: Rectangle) -> float:
    return r.area()
